package com.example.mfa.service;

import com.example.mfa.model.AppUser;
import com.example.mfa.repository.AppUserRepository;
import java.util.Optional;
import org.springframework.security.crypto.password.PasswordEncoder;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

@Service
public class UserService {

    private final AppUserRepository appUserRepository;
    private final PasswordEncoder passwordEncoder;

    public UserService(AppUserRepository appUserRepository, PasswordEncoder passwordEncoder) {
        this.appUserRepository = appUserRepository;
        this.passwordEncoder = passwordEncoder;
    }

    @Transactional
    public AppUser register(String username, String password) {
        Optional<AppUser> existing = appUserRepository.findByUsername(username);
        if (existing.isPresent()) {
            throw new IllegalArgumentException("Username already exists");
        }
        AppUser user = new AppUser();
        user.setUsername(username);
        user.setPasswordHash(passwordEncoder.encode(password));
        return appUserRepository.save(user);
    }

    public AppUser getByUsername(String username) {
        return appUserRepository.findByUsername(username)
                .orElseThrow(() -> new IllegalArgumentException("User not found"));
    }

    @Transactional
    public AppUser save(AppUser user) {
        return appUserRepository.save(user);
    }
}

package com.example.mfa.service;

import com.example.mfa.model.AppUser;
import com.example.mfa.model.BackupCode;
import com.example.mfa.repository.BackupCodeRepository;
import java.security.SecureRandom;
import java.time.Instant;
import java.util.ArrayList;
import java.util.List;
import org.springframework.security.crypto.password.PasswordEncoder;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

@Service
public class BackupCodeService {

    private static final String CHARS = "ABCDEFGHJKLMNPQRSTUVWXYZ23456789";
    private static final int CODE_COUNT = 10;
    private static final int CODE_LENGTH = 10;

    private final BackupCodeRepository backupCodeRepository;
    private final PasswordEncoder passwordEncoder;
    private final SecureRandom secureRandom = new SecureRandom();

    public BackupCodeService(BackupCodeRepository backupCodeRepository, PasswordEncoder passwordEncoder) {
        this.backupCodeRepository = backupCodeRepository;
        this.passwordEncoder = passwordEncoder;
    }

    @Transactional
    public List<String> regenerateBackupCodes(AppUser user) {
        backupCodeRepository.deleteByUser(user);
        List<String> plainCodes = new ArrayList<>();
        List<BackupCode> entities = new ArrayList<>();

        for (int i = 0; i < CODE_COUNT; i++) {
            String code = generateReadableCode();
            plainCodes.add(code);

            BackupCode backupCode = new BackupCode();
            backupCode.setUser(user);
            backupCode.setCodeHash(passwordEncoder.encode(code));
            entities.add(backupCode);
        }

        backupCodeRepository.saveAll(entities);
        return plainCodes;
    }

    @Transactional
    public boolean consumeBackupCode(AppUser user, String rawCode) {
        List<BackupCode> codes = backupCodeRepository.findByUserAndUsedFalse(user);
        for (BackupCode code : codes) {
            if (passwordEncoder.matches(normalize(rawCode), code.getCodeHash())) {
                code.setUsed(true);
                code.setUsedAt(Instant.now());
                backupCodeRepository.save(code);
                return true;
            }
        }
        return false;
    }

    private String generateReadableCode() {
        StringBuilder sb = new StringBuilder();
        for (int i = 0; i < CODE_LENGTH; i++) {
            sb.append(CHARS.charAt(secureRandom.nextInt(CHARS.length())));
        }
        String raw = sb.toString();
        return raw.substring(0, 5) + "-" + raw.substring(5);
    }

    private String normalize(String code) {
        return code == null ? "" : code.replace("-", "").replace(" ", "").toUpperCase();
    }
}

package com.example.mfa.service;

import com.example.mfa.model.AppUser;
import java.nio.ByteBuffer;
import java.time.Instant;
import javax.crypto.Mac;
import javax.crypto.spec.SecretKeySpec;
import org.springframework.stereotype.Service;

@Service
public class TotpService {

    public boolean verifyCode(AppUser user, String code) {
        if (user.getTotpSecret() == null || code == null || code.isBlank()) {
            return false;
        }
        long currentTimeWindow = Instant.now().getEpochSecond() / 30;
        for (int i = -1; i <= 1; i++) {
            String generated = generateTotp(user.getTotpSecret(), currentTimeWindow + i);
            if (generated.equals(code)) {
                return true;
            }
        }
        return false;
    }

    private String generateTotp(String secret, long counter) {
        try {
            byte[] key = secret.getBytes();
            ByteBuffer buffer = ByteBuffer.allocate(8);
            buffer.putLong(counter);
            byte[] counterBytes = buffer.array();

            Mac mac = Mac.getInstance("HmacSHA1");
            mac.init(new SecretKeySpec(key, "HmacSHA1"));
            byte[] hash = mac.doFinal(counterBytes);

            int offset = hash[hash.length - 1] & 0xF;
            int binary = ((hash[offset] & 0x7F) << 24)
                    | ((hash[offset + 1] & 0xFF) << 16)
                    | ((hash[offset + 2] & 0xFF) << 8)
                    | (hash[offset + 3] & 0xFF);

            int otp = binary % 1_000_000;
            return String.format("%06d", otp);
        } catch (Exception e) {
            return "";
        }
    }
}

package com.example.mfa.service;

import com.example.mfa.dto.AuthResponse;
import com.example.mfa.model.AppUser;
import com.example.mfa.model.MfaType;
import org.springframework.security.crypto.password.PasswordEncoder;
import org.springframework.stereotype.Service;

@Service
public class AuthenticationService {

    private final UserService userService;
    private final PasswordEncoder passwordEncoder;
    private final TotpService totpService;
    private final BackupCodeService backupCodeService;

    public AuthenticationService(
            UserService userService,
            PasswordEncoder passwordEncoder,
            TotpService totpService,
            BackupCodeService backupCodeService) {
        this.userService = userService;
        this.passwordEncoder = passwordEncoder;
        this.totpService = totpService;
        this.backupCodeService = backupCodeService;
    }

    public AuthResponse authenticate(String username, String password, String totpCode, String backupCode) {
        AppUser user = userService.getByUsername(username);
        if (!user.isAccountNonLocked()) {
            return new AuthResponse(false, null, "Account is locked");
        }
        if (!passwordEncoder.matches(password, user.getPasswordHash())) {
            return new AuthResponse(false, null, "Invalid credentials");
        }

        if (!user.isMfaEnabled()) {
            return new AuthResponse(true, null, "Authenticated without MFA");
        }

        if (totpCode != null && !totpCode.isBlank() && totpService.verifyCode(user, totpCode)) {
            return new AuthResponse(true, MfaType.TOTP.name(), "Authenticated with TOTP");
        }

        if (backupCode != null && !backupCode.isBlank() && backupCodeService.consumeBackupCode(user, backupCode)) {
            return new AuthResponse(true, MfaType.BACKUP_CODE.name(), "Authenticated with backup code");
        }

        return new AuthResponse(false, null, "MFA verification failed");
    }
}

package com.example.mfa.controller;

import com.example.mfa.dto.AuthResponse;
import com.example.mfa.dto.LoginRequest;
import com.example.mfa.dto.RegisterRequest;
import com.example.mfa.model.AppUser;
import com.example.mfa.service.AuthenticationService;
import com.example.mfa.service.UserService;
import jakarta.validation.Valid;
import org.springframework.http.HttpStatus;
import org.springframework.web.bind.annotation.*;

@RestController
@RequestMapping("/api/auth")
public class AuthController {

    private final UserService userService;
    private final AuthenticationService authenticationService;

    public AuthController(UserService userService, AuthenticationService authenticationService) {
        this.userService = userService;
        this.authenticationService = authenticationService;
    }

    @PostMapping("/register")
    @ResponseStatus(HttpStatus.CREATED)
    public String register(@Valid @RequestBody RegisterRequest request) {
        AppUser user = userService.register(request.getUsername(), request.getPassword());
        return "Registered user with id " + user.getId();
    }

    @PostMapping("/login")
    public AuthResponse login(@Valid @RequestBody LoginRequest request) {
        return authenticationService.authenticate(
                request.getUsername(),
                request.getPassword(),
                request.getTotpCode(),
                request.getBackupCode());
    }
}

package com.example.mfa.controller;

import com.example.mfa.dto.BackupCodesResponse;
import com.example.mfa.dto.EnableMfaRequest;
import com.example.mfa.model.AppUser;
import com.example.mfa.service.BackupCodeService;
import com.example.mfa.service.UserService;
import jakarta.validation.Valid;
import java.util.List;
import org.springframework.web.bind.annotation.*;

@RestController
@RequestMapping("/api/mfa")
public class MfaController {

    private final UserService userService;
    private final BackupCodeService backupCodeService;

    public MfaController(UserService userService, BackupCodeService backupCodeService) {
        this.userService = userService;
        this.backupCodeService = backupCodeService;
    }

    @PostMapping("/{username}/enable")
    public BackupCodesResponse enableMfa(@PathVariable String username, @Valid @RequestBody EnableMfaRequest request) {
        AppUser user = userService.getByUsername(username);
        user.setMfaEnabled(true);
        user.setTotpSecret(request.getTotpSecret());
        userService.save(user);
        List<String> backupCodes = backupCodeService.regenerateBackupCodes(user);
        return new BackupCodesResponse(backupCodes);
    }

    @PostMapping("/{username}/backup-codes/regenerate")
    public BackupCodesResponse regenerateBackupCodes(@PathVariable String username) {
        AppUser user = userService.getByUsername(username);
        List<String> backupCodes = backupCodeService.regenerateBackupCodes(user);
        return new BackupCodesResponse(backupCodes);
    }
}

